public class Conditionals {
    public static void main(String[] args) {
        int score = 85;

        // Structure if-else-if
        System.out.println("Score: " + score);
        if (score >= 90) {
            System.out.println("Mention: Excellent! 🌟");
        } else if (score >= 80) {
            System.out.println("Mention: Très bien! 👍");
        } else if (score >= 70) {
            System.out.println("Mention: Bien ✓");
        } else if (score >= 60) {
            System.out.println("Mention: Passable");
        } else {
            System.out.println("Mention: Insuffisant ❌");
        }

        // Switch avec enum simulé
        char grade = 'B';
        System.out.println("\nNote: " + grade);
        switch (grade) {
            case 'A':
                System.out.println("Parfait! Continue ainsi!");
                break;
            case 'B':
                System.out.println("Bon travail! Encore un effort!");
                break;
            case 'C':
                System.out.println("Acceptable, mais peut mieux faire");
                break;
            case 'D':
                System.out.println("Insuffisant, il faut travailler");
                break;
            default:
                System.out.println("Note non reconnue");
        }

        // Conditions complexes
        boolean hasLicense = true;
        int drivingAge = 20;
        if (hasLicense && drivingAge >= 18) {
            System.out.println("\n🚗 Autorisé à conduire");
        } else {
            System.out.println("\n🚫 Non autorisé à conduire");
        }
    }
}

