public class Loops {
    public static void main(String[] args) {
        // Boucle for classique
        System.out.println("=== Boucle for classique ===");
        for (int i = 1; i <= 5; i++) {
            System.out.println("Itération " + i + ": " + (i * i));
        }

        // Boucle while
        System.out.println("\n=== Boucle while ===");
        int count = 10;
        while (count > 0) {
            System.out.println("Compte à rebours: " + count);
            count -= 2; // Décrémente de 2
        }

        // Boucle do-while
        System.out.println("\n=== Boucle do-while ===");
        int num = 1;
        do {
            System.out.println("Nombre: " + num + " (carré: " + (num * num) + ")");
            num++;
        } while (num <= 4);

        // Boucles imbriquées - Table de multiplication
        System.out.println("\n=== Table de multiplication (3x3) ===");
        for (int i = 1; i <= 3; i++) {
            for (int j = 1; j <= 3; j++) {
                System.out.printf("%2d ", i * j);
            }
            System.out.println(); // Nouvelle ligne
        }

        // Utilisation de break et continue
        System.out.println("\n=== Nombres pairs de 1 à 10 ===");
        for (int i = 1; i <= 10; i++) {
            if (i % 2 != 0) {
                continue; // Passe au suivant si impair
            }
            System.out.print(i + " ");
            if (i == 8) {
                break; // Arrête à 8
            }
        }
        System.out.println();
    }
}

