public class Arrays {
    public static void main(String[] args) {
        // Déclaration et initialisation
        int[] numbers = {10, 25, 7, 42, 15};
        String[] fruits = {"Pomme", "Banane", "Orange", "Fraise"};

        System.out.println("=== Parcours avec index ===");
        for (int i = 0; i < numbers.length; i++) {
            System.out.println("Index " + i + ": " + numbers[i]);
        }

        System.out.println("\n=== Parcours for-each ===");
        for (String fruit : fruits) {
            System.out.println("🍎 " + fruit);
        }

        // Opérations sur tableaux
        System.out.println("\n=== Statistiques ===");
        int sum = 0, max = numbers[0], min = numbers[0];
        for (int num : numbers) {
            sum += num;
            max = Math.max(max, num);
            min = Math.min(min, num);
        }
        System.out.println("Somme: " + sum);
        System.out.println("Moyenne: " + (sum / (double) numbers.length));
        System.out.println("Maximum: " + max);
        System.out.println("Minimum: " + min);

        // Tableau 2D - Matrice
        int[][] matrix = {
            {1, 2, 3},
            {4, 5, 6},
            {7, 8, 9}
        };

        System.out.println("\n=== Matrice 3x3 ===");
        for (int i = 0; i < matrix.length; i++) {
 for (int j = 0; j < matrix[i].length; j++) {
   System.out.printf("%3d ", matrix[i][j]);
            }
            System.out.println();
        }

        // Recherche dans un tableau
        System.out.println("\n=== Recherche ===");
        String searchFruit = "Orange";
        boolean found = false;
        int position = -1;
        for (int i = 0; i < fruits.length; i++) {
            if (fruits[i].equals(searchFruit)) {
                found = true;
                position = i;
                break;
            }
        }
        System.out.println(searchFruit + (found ? " trouvé à la position " + position : " non trouvé"));

        // Tri simple (bubble sort)
        int[] toSort = {64, 34, 25, 12, 22, 11, 90};
        System.out.println("\n=== Tri (avant): " + java.util.Arrays.toString(toSort));
        bubbleSort(toSort);
        System.out.println("=== Tri (après): " + java.util.Arrays.toString(toSort));
    }

    private static void bubbleSort(int[] arr) {
  int n = arr.length;
  for (int i = 0; i < n - 1; i++) {
  for (int j = 0; j < n - i - 1; j++) {
 if (arr[j] > arr[j + 1]) {
     // Échange
  int temp = arr[j];
   arr[j] = arr[j + 1];
  arr[j + 1] = temp;
  }
  }
  }
    }
}

