// Classe représentant un compte bancaire
class BankAccount {
    // Attributs privés (encapsulation)
    private String accountNumber;
    private String ownerName;
    private double balance;
    private static int accountCounter = 1000;

    // Constructeur
    public BankAccount(String ownerName, double initialBalance) {
        this.accountNumber = "ACC" + (++accountCounter);
        this.ownerName = ownerName;
        this.balance = Math.max(0, initialBalance); // Pas de solde négatif initial
    }

    // Méthodes d'accès (getters)
    public String getAccountNumber() { return accountNumber; }
    public String getOwnerName() { return ownerName; }
    public double getBalance() { return balance; }

    // Méthodes métier
    public boolean deposit(double amount) {
        if (amount > 0) {
            balance += amount;
            System.out.println("💰 Dépôt de " + amount + "€ effectué.");
            return true;
        }
        System.out.println("❌ Montant invalide pour le dépôt.");
        return false;
    }

    public boolean withdraw(double amount) {
        if (amount > 0 && amount <= balance) {
            balance -= amount;
            System.out.println("💸 Retrait de " + amount + "€ effectué.");
            return true;
        }
        System.out.println("❌ Retrait impossible (solde insuffisant ou montant invalide).");
        return false;
    }

    public boolean transfer(BankAccount destinationAccount, double amount) {
        if (this.withdraw(amount)) {
            destinationAccount.deposit(amount);
            System.out.println("🔄 Virement de " + amount + "€ vers " + destinationAccount.getOwnerName());
            return true;
        }
        return false;
    }

    public void displayAccountInfo() {
        System.out.println("\n=== Informations du compte ===");
        System.out.println("Numéro: " + accountNumber);
        System.out.println("Titulaire: " + ownerName);
        System.out.printf("Solde: %.2f€%n", balance);
    }

    // Méthode toString pour affichage
    @Override
    public String toString() {
        return String.format("BankAccount{%s, %s, %.2f€}", 
                           accountNumber, ownerName, balance);
    }
}

public class OOPExample {
    public static void main(String[] args) {
        System.out.println("=== SYSTÈME BANCAIRE ===");

        // Création des comptes
        BankAccount account1 = new BankAccount("Alice Martin", 1000.0);
        BankAccount account2 = new BankAccount("Bob Durand", 500.0);

        // Affichage initial
        account1.displayAccountInfo();
        account2.displayAccountInfo();

        System.out.println("\n=== OPÉRATIONS ===");

        // Opérations sur les comptes
        account1.deposit(200);
        account1.withdraw(150);
        account2.deposit(50);

        // Virement
        System.out.println("\n--- Virement ---");
        account1.transfer(account2, 300);

        // État final
        System.out.println("\n=== ÉTAT FINAL ===");
        account1.displayAccountInfo();
        account2.displayAccountInfo();

        // Test des cas d'erreur
        System.out.println("\n=== TESTS D'ERREUR ===");
        account1.withdraw(2000); // Solde insuffisant
        account1.deposit(-100);  // Montant négatif
    }
}

