// Classe abstraite de base
abstract class Vehicle {
    protected String brand;
    protected String model;
    protected int year;
    protected double price;

    public Vehicle(String brand, String model, int year, double price) {
        this.brand = brand;
        this.model = model;
        this.year = year;
        this.price = price;
    }

    // Méthode abstraite à implémenter
    public abstract void start();
    public abstract double calculateInsurance();

    // Méthodes communes
    public void displayInfo() {
        System.out.printf("%s %s (%d) - %.2f€%n", brand, model, year, price);
    }

    public int getAge() {
        return 2024 - year;
    }

    // Getters
    public String getBrand() { return brand; }
    public String getModel() { return model; }
    public double getPrice() { return price; }
}

// Classe dérivée: Voiture
class Car extends Vehicle {
    private int doors;
    private String fuelType;

    public Car(String brand, String model, int year, double price, int doors, String fuelType) {
        super(brand, model, year, price);
        this.doors = doors;
        this.fuelType = fuelType;
    }

    @Override
    public void start() {
        System.out.println("🚗 " + brand + " " + model + " démarre avec la clé.");
    }

    @Override
    public double calculateInsurance() {
        double baseRate = price * 0.05; // 5% du prix
        if (getAge() > 10) baseRate *= 0.8; // Réduction pour véhicules anciens
        return baseRate;
    }

    @Override
    public void displayInfo() {
        super.displayInfo();
        System.out.println("  Type: Voiture (" + doors + " portes, " + fuelType + ")");
    }

    public void openTrunk() {
        System.out.println("🧳 Coffre ouvert.");
    }
}

// Classe dérivée: Moto
class Motorcycle extends Vehicle {
    private int engineSize;
    private boolean hasSidecar;

    public Motorcycle(String brand, String model, int year, double price, int engineSize, boolean hasSidecar) {
        super(brand, model, year, price);
        this.engineSize = engineSize;
        this.hasSidecar = hasSidecar;
    }

    @Override
    public void start() {
        System.out.println("🏍️ " + brand + " " + model + " démarre avec le bouton de démarrage.");
    }

    @Override
    public double calculateInsurance() {
        double baseRate = price * 0.08; // 8% du prix (plus risqué)
        if (engineSize > 600) baseRate *= 1.5; // Majoration pour grosses cylindrées
        if (hasSidecar) baseRate *= 0.9; // Réduction pour side-car (plus stable)
        return baseRate;
    }

    @Override
    public void displayInfo() {
        super.displayInfo();
        System.out.println("  Type: Moto (" + engineSize + "cc" + (hasSidecar ? ", avec side-car" : "") + ")");
    }

    public void wheelie() {
        if (engineSize > 250) {
            System.out.println("🤸 Wheelie réalisé!");
        } else {
            System.out.println("❌ Cylindrée trop faible pour un wheelie.");
        }
    }
}

// Classe dérivée: Camion
class Truck extends Vehicle {
    private double maxLoad;
    private int axles;

    public Truck(String brand, String model, int year, double price, double maxLoad, int axles) {
        super(brand, model, year, price);
        this.maxLoad = maxLoad;
        this.axles = axles;
    }

    @Override
    public void start() {
        System.out.println("🚛 " + brand + " " + model + " démarre avec un rugissement.");
    }

    @Override
    public double calculateInsurance() {
        double baseRate = price * 0.06; // 6% du prix
        baseRate += maxLoad * 10; // Majoration selon la charge utile
        return baseRate;
    }

    @Override
    public void displayInfo() {
        super.displayInfo();
        System.out.println("  Type: Camion (" + maxLoad + "t, " + axles + " essieux)");
    }

    public void loadCargo(double weight) {
        if (weight <= maxLoad) {
            System.out.println("📦 Chargement de " + weight + "t effectué.");
        } else {
            System.out.println("❌ Surcharge! Capacité maximale: " + maxLoad + "t");
        }
    }
}

public class InheritanceExample {
    public static void main(String[] args) {
        System.out.println("=== GARAGE AUTOMOBILE ===");

        // Création du parc de véhicules
        Vehicle[] vehicles = {
            new Car("Toyota", "Corolla", 2020, 25000, 4, "Essence"),
            new Car("Tesla", "Model 3", 2023, 45000, 4, "Électrique"),
            new Motorcycle("Yamaha", "MT-07", 2021, 8000, 689, false),
            new Motorcycle("Harley-Davidson", "Sportster", 2019, 15000, 883, true),
            new Truck("Volvo", "FH16", 2018, 80000, 25.0, 3)
        };

        // Affichage des informations (polymorphisme)
        System.out.println("\n=== INVENTAIRE ===");
        for (int i = 0; i < vehicles.length; i++) {
            System.out.println("\n" + (i + 1) + ". ");
            vehicles[i].displayInfo();
            System.out.printf("   Assurance annuelle: %.2f€%n", vehicles[i].calculateInsurance());
        }

        // Démonstration du polymorphisme
        System.out.println("\n=== DÉMARRAGE DES VÉHICULES ===");
        for (Vehicle vehicle : vehicles) {
            vehicle.start();
        }

        // Utilisation des méthodes spécifiques
        System.out.println("\n=== FONCTIONNALITÉS SPÉCIFIQUES ===");

        // Cast et vérification de type
        for (Vehicle vehicle : vehicles) {
            if (vehicle instanceof Car) {
                Car car = (Car) vehicle;
                car.openTrunk();
            } else if (vehicle instanceof Motorcycle) {
                Motorcycle moto = (Motorcycle) vehicle;
                moto.wheelie();
            } else if (vehicle instanceof Truck) {
                Truck truck = (Truck) vehicle;
                truck.loadCargo(20.0);
            }
        }

        // Statistiques
        System.out.println("\n=== STATISTIQUES ===");
        double totalValue = 0;
        double totalInsurance = 0;
        int carCount = 0, motoCount = 0, truckCount = 0;

        for (Vehicle vehicle : vehicles) {
            totalValue += vehicle.getPrice();
            totalInsurance += vehicle.calculateInsurance();

            if (vehicle instanceof Car) carCount++;
            else if (vehicle instanceof Motorcycle) motoCount++;
            else if (vehicle instanceof Truck) truckCount++;
        }

        System.out.println("Nombre total de véhicules: " + vehicles.length);
        System.out.println("  - Voitures: " + carCount);
        System.out.println("  - Motos: " + motoCount);
        System.out.println("  - Camions: " + truckCount);
        System.out.printf("Valeur totale: %.2f€%n", totalValue);
        System.out.printf("Coût total assurance: %.2f€%n", totalInsurance);
    }
}
